const raw = $input.first().json.output;
let text = typeof raw === "string" ? raw : JSON.stringify(raw);

text = text.trim();
if (text.startsWith('```')) {
  text = text.replace(/^```[a-zA-Z]*\n?/, '');
  text = text.replace(/```$/, '');
  text = text.trim();
}

const config = JSON.parse(text);

const ALLOWED_SENIORITY = [
  "founder","owner","c_suite","director","vp","head","manager","senior","entry","trainee"
];

const ALLOWED_FUNCTIONAL = [
  "c_suite","finance","product_management","engineering","design",
  "education","human_resources","information_technology","legal",
  "marketing","operations","sales","support"
];

const ALLOWED_SIZE = [
  "1-10","11-20","21-50","51-100","101-200","201-500",
  "501-1000","1001-2000","2001-5000","5001-10000",
  "10001-20000","20001-50000","50000+"
];

const ALLOWED_INDUSTRY = [
  "information technology & services","computer software","internet","marketing & advertising",
  "retail","financial services","consumer services","hospital & health care","automotive",
  "restaurants","education management","food & beverages","design","hospitality","accounting",
  "events services","nonprofit organization management","entertainment",
  "electrical/electronic manufacturing","leisure, travel & tourism",
  "professional training & coaching","transportation/trucking/railroad","law practice",
  "apparel & fashion","architecture & planning","mechanical or industrial engineering",
  "insurance","telecommunications","human resources","staffing & recruiting","sports",
  "legal services","oil & energy","media production","machinery","wholesale","consumer goods",
  "music","photography","medical practice","cosmetics","environmental services","graphic design",
  "business supplies & equipment","renewables & environment","facilities services","publishing",
  "food production","arts & crafts","building materials","civil engineering",
  "religious institutions","public relations & communications","higher education","printing",
  "furniture","mining & metals","logistics & supply chain","research","pharmaceuticals",
  "individual & family services","medical devices","civic & social organization","e-learning",
  "security & investigations","chemicals","government administration","online media",
  "investment management","farming","writing & editing","textiles","mental health care",
  "primary/secondary education","broadcast media","biotechnology","information services",
  "international trade & development","motion pictures & film","consumer electronics","banking",
  "import & export","industrial automation","recreational facilities & services","performing arts",
  "utilities","sporting goods","fine art","airlines/aviation","computer & network security",
  "maritime","luxury goods & jewelry","veterinary","venture capital & private equity",
  "wine & spirits","plastics","aviation & aerospace","commercial real estate","computer games",
  "packaging & containers","executive office","computer hardware","computer networking",
  "market research","outsourcing/offshoring","program development","translation & localization",
  "philanthropy","public safety","alternative medicine","museums & institutions","warehousing",
  "defense & space","newspapers","paper & forest products","law enforcement","investment banking",
  "government relations","fund-raising","think tanks","glass, ceramics & concrete",
  "capital markets","semiconductors","animation","political organization",
  "package/freight delivery","wireless","international affairs","public policy","libraries",
  "gambling & casinos","railroad manufacture","ranching","military","fishery","supermarkets",
  "dairy","tobacco","shipbuilding","judiciary","alternative dispute resolution","nanotechnology",
  "agriculture","legislative office"
];

const uniq = (arr) => Array.from(new Set(arr));

function sanitizeSeniorityLevel(values) {
  if (!Array.isArray(values)) return [];
  const mapped = values
    .map((v) => String(v).toLowerCase().trim())
    .map((v) => {
      if (["c-level","c level","c-suite","csuite"].includes(v)) return "c_suite";
      return v;
    })
    .filter((v) => ALLOWED_SENIORITY.includes(v));
  if (mapped.length === 0) {
    return ["owner","founder","c_suite","vp","director","head","manager"];
  }
  return uniq(mapped);
}

function sanitizeFunctionalLevel(values) {
  if (!Array.isArray(values)) return [];
  const mapped = values
    .map((v) => String(v).toLowerCase().trim())
    .map((v) => {
      if (v === "growth") return "marketing";
      if (v === "gtm") return "marketing";
      if (v === "product") return "product_management";
      if (v === "product management") return "product_management";
      if (v === "engineering & product") return "engineering";
      if (v === "hr") return "human_resources";
      if (v === "it") return "information_technology";
      return v;
    })
    .filter((v) => ALLOWED_FUNCTIONAL.includes(v));
  if (mapped.length === 0) {
    return ["marketing","sales","operations"];
  }
  return uniq(mapped);
}

function expandSizeRange(v) {
  if (ALLOWED_SIZE.includes(v)) return [v];
  if (v === "0-1") return ["1-10"];
  if (v === "1-10") return ["1-10"];
  if (v === "2-10") return ["1-10"];
  if (v === "11-50") return ["11-20","21-50"];
  if (v === "51-200") return ["51-100","101-200"];
  if (v === "11-100") return ["11-20","21-50","51-100"];
  if (v === "10000+") return ["5001-10000","10001-20000"];
  return [];
}

function sanitizeSize(values) {
  if (!Array.isArray(values)) return [];
  const expanded = values
    .map((v) => String(v).toLowerCase().trim())
    .flatMap(expandSizeRange)
    .filter((v) => ALLOWED_SIZE.includes(v));
  if (expanded.length === 0) {
    return ["11-20","21-50","51-100","101-200","201-500"];
  }
  return uniq(expanded);
}

function mapIndustry(v) {
  const x = v.toLowerCase().trim();
  if (ALLOWED_INDUSTRY.includes(x)) return x;
  if (x === "information technology" || x === "it services") return "information technology & services";
  if (x === "software" || x === "saas") return "computer software";
  if (x === "ecommerce" || x === "e-commerce") return "retail";
  if (x === "healthcare") return "hospital & health care";
  if (x === "marketing") return "marketing & advertising";
  if (x === "education") return "education management";
  if (x === "auto" || x === "car dealership" || x === "autobody") return "automotive";
  return null;
}

function sanitizeCompanyIndustry(values) {
  if (!Array.isArray(values)) return [];
  const mapped = values
    .map((v) => mapIndustry(String(v)))
    .filter((v) => !!v)
    .filter((v) => ALLOWED_INDUSTRY.includes(v));
  return uniq(mapped);
}

function sanitizeContactLocation(values) {
  if (!Array.isArray(values)) return [];
  const mapped = values
    .map((v) => String(v).toLowerCase().trim())
    .map((v) => {
      if (["usa","us","u.s.","united states of america"].includes(v)) return "united states";
      if (["uk","u.k."].includes(v)) return "united kingdom";
      return v;
    });
  return uniq(mapped);
}

function sanitizeApolloPersonSeniorities(values) {
  if (!Array.isArray(values)) return [];
  const mapped = values
    .map((v) => String(v).toLowerCase().trim())
    .map((v) => {
      if (["c-suite","c level","c-level","csuite"].includes(v)) return "c_suite";
      return v;
    })
    .filter((v) => ALLOWED_SENIORITY.includes(v));
  if (mapped.length === 0) {
    return ["founder","owner","c_suite","vp","director","head","manager"];
  }
  return uniq(mapped);
}

const cleanConfig = JSON.parse(JSON.stringify(config));

if (cleanConfig.leads_finder) {
  cleanConfig.leads_finder.seniority_level =
    sanitizeSeniorityLevel(cleanConfig.leads_finder.seniority_level);
  cleanConfig.leads_finder.functional_level =
    sanitizeFunctionalLevel(cleanConfig.leads_finder.functional_level);
  cleanConfig.leads_finder.size =
    sanitizeSize(cleanConfig.leads_finder.size);
  cleanConfig.leads_finder.company_industry =
    sanitizeCompanyIndustry(cleanConfig.leads_finder.company_industry);
  cleanConfig.leads_finder.contact_location =
    sanitizeContactLocation(cleanConfig.leads_finder.contact_location);
}

if (cleanConfig.apollo) {
  cleanConfig.apollo.person_seniorities =
    sanitizeApolloPersonSeniorities(cleanConfig.apollo.person_seniorities);
  if (typeof cleanConfig.apollo.q_keywords === 'string') {
    cleanConfig.apollo.q_keywords = cleanConfig.apollo.q_keywords
      .split(',')
      .map(p => p.trim())
      .filter(p => p.length > 0)
      .slice(0, 15)
      .join(', ');
  }
}

return [{ json: { cleanConfig } }];

const items = $input.all();

let campaignId = $('Data Cleaning').first().json.cleanConfig.campaign_id;
for (const it of items) {
  if (it.json.campaign_id) { campaignId = it.json.campaign_id; break; }
  if (it.json.cleanConfig && it.json.cleanConfig.campaign_id) { campaignId = it.json.cleanConfig.campaign_id; break; }
}

const leads = [];

for (const item of items) {
  const p = item.json || {};

  const emails = Array.isArray(p.emails) ? p.emails : [];
  const email = (emails[0] || '').trim();
  if (!email) continue;

  const rawPhone = String(p.phone || '').replace(/\D/g, '');
  if (!rawPhone) continue;

  const company_name = (p.title || p.name || '').trim();

  let website = (p.website || '').trim();
  if (website && !website.startsWith('http')) website = 'https://' + website;

  const city = (p.city || '').trim();
  const country = (p.country || '').trim();

  let linkedin_url = '';
  if (Array.isArray(p.linkedIns) && p.linkedIns.length > 0) {
    linkedin_url = (p.linkedIns[0] || '').trim();
  }

  leads.push({
    json: {
      source: 'gmaps',
      campaign_id: campaignId,
      first_name: '',
      last_name: '',
      title: '',
      company_name,
      email,
      phone: rawPhone,
      website,
      city,
      country,
      linkedin_url,
      email_status: 'unchecked',
    },
  });
}

return leads;

